Updated on 2020-03-15
https://www.lua.org/download.html
Step pacman -Syu pacman -S --noconfirm --needed gcc make curl -O https://www.lua.org/ftp/lua-5.4.0.tar.gz tar zxf lua-5.4.0.tar.gz cd lua-5.4.0 make posix install CC=&#39;x86_64-pc-msys-gcc&#39;

Updated on 2019-05-10
OpenSSL
Step docker pull gcc:latest curl https://mirrors.cloud.tencent.com/openssl/source/openssl-1.1.1e.tar.gz | tar -xz &amp;&amp; cd openssl-1.1.1b docker run --rm -v `pwd`:`pwd` -w `pwd` gcc:latest sh -c &#39;mkdir build &amp;&amp; cd build &amp;&amp; ../config no-deprecated no-shared no-tests -static --prefix=`pwd`/123 &amp;&amp; make install_sw&#39;

Updated on 2019-04-04 Linux curl -o /etc/yum.repos.d/CentOS-Base.repo https://mirrors.aliyun.com/repo/Centos-7.repo yum makecache yum update -y timedatectl set-timezone Asia/Shanghai date +%s -s @1602842120 hwclock -w Docker https://docs.docker.com/reference/ https://docs.docker.com/engine/reference/builder/ https://docs.docker.com/engine/reference/commandline/docker/ https://docs.docker.com/engine/reference/commandline/dockerd/ curl -fsSL https://get.docker.com | bash -s -- docker --mirror Aliyun mkdir -p /etc/docker echo -e &#39;{
&#34;userland-proxy&#34;: false,
&#34;registry-mirrors&#34;: [&#34;https://docker.mirrors.ustc.edu.cn&#34;]
}&#39; &gt; /etc/docker/daemon.json systemctl start docker systemctl enable docker systemctl status docker usermod -aG docker leo docker ps -a #查看容器 docker images #查看镜像 docker network ls #查看网络 docker rm -fv gitlab #停止并删除容器、卷 docker rm `docker ps -a -q` #删除已停止的容器 docker rmi gitlab/gitlab-ce #删除镜像 docker image prune -f #清除未使用镜像 docker logs -f gitlab #查看容器日志 docker exec -it gitlab sh #获得容器 Shell docker system info #查看系统信息 docker system df #查看磁盘占用 docker system prune --volumes #清除未使用数据 Docker Compose https://docs.
